import{_ as n,g as i,f as h,z as a}from"./chunks/framework.5qxeQQbV.js";const l=JSON.parse('{"title":"Kinh Từ Bi","description":"Bài kinh về việc tu tập tâm từ đến muôn loài chúng sinh.","frontmatter":{"code":"Kt.","title":"Kinh Từ Bi","pali":"Metta Sutta (Sutta Nipāta)","group":"Thi kệ & giáo huấn","translation":"thich-minh-chau","book":"tieu-bo","description":"Bài kinh về việc tu tập tâm từ đến muôn loài chúng sinh."},"headers":[],"relativePath":"kinh/tieu-bo/thich-minh-chau/sn-metta-kinh-tu-bi.md","filePath":"kinh/tieu-bo/thich-minh-chau/sn-metta-kinh-tu-bi.md","lastUpdated":1782983601000}'),o={name:"kinh/tieu-bo/thich-minh-chau/sn-metta-kinh-tu-bi.md"};function e(c,t,m,u,g,s){return i(),h("div",null,[...t[0]||(t[0]=[a("<p><em>Như vầy tôi nghe.</em></p><p>Một thời Thế Tôn trú tại Savatthi. Tại đó, Thế Tôn nói với các Tỳ-kheo về cách tu tập tâm từ:</p><blockquote><p>&quot;Ai muốn đạt được sự an lạc, hãy nên khéo thành tựu tâm từ. Ai muốn sống an vui, không bị ai hãm hại, hãy nuôi dưỡng tâm từ đối với mọi chúng sinh.&quot;</p></blockquote><p>Hãy đứng, đi, ngồi, nằm — trong khi còn tỉnh táo — luôn giữ tâm từ. Đây là sự sống thiêng liêng nhất.</p><p>Không nên lầm lỗi với bất cứ ai; không nên khinh miệt hay ganh tỵ. Trong khổ đau hay hạnh phúc, hãy giữ tâm không lay chuyển, luôn rộng mở và từ bi đối với toàn thể chúng sinh.</p><blockquote><p>&quot;Như một người mẹ che chở đứa con duy nhất của mình bằng tất cả tấm lòng, hãy rải tâm từ đến muôn loài — trên, dưới, ngang, dọc — bao trùm toàn thể thế gian, không còn sân hận hay thù oán.&quot;</p></blockquote><p>Khi đứng, đi, ngồi, nằm, miên mãt không mệt mỏi, hãy giữ tâm từ này. Đây được gọi là <em>sự sống thiêng liêng tối thượng</em>.</p><hr>",8)])])}const r=n(o,[["render",e]]);export{l as __pageData,r as default};
